'use client';

import { track } from '@/services/analytics-service';
import { trackClevertap } from '@/utils/clevertap';

export interface DownloadPromptConfig {
  icon: React.ReactNode;
  title: string;
  description: string;
  primaryCtaText: string;
  secondaryCtaText: string;
}

export type PromptMilestone = 'messages_5' | 'messages_10' | 'messages_15';

interface DownloadPromptModalProps {
  config: DownloadPromptConfig;
  milestone: PromptMilestone;
  onPrimaryClick: () => void;
  onSecondaryClick: () => void;
}

export function DownloadPromptModal({
  config,
  milestone,
  onPrimaryClick,
  onSecondaryClick,
}: DownloadPromptModalProps) {
  const handlePrimaryClick = () => {
    track('download_prompt_primary_clicked', { milestone });
    trackClevertap('Modal Primary CTA Clicked', { name: 'app-update', button_copy: 'Download' });
    onPrimaryClick();
  };

  const handleSecondaryClick = () => {
    track('download_prompt_secondary_clicked', { milestone });
    trackClevertap('Modal Secondary CTA Clicked', { name: 'app-update', button_copy: 'Dismiss' });
    onSecondaryClick();
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center px-4 py-8">
      {/* Backdrop */}
      <div
        className="absolute inset-0"
        style={{
          backgroundColor: 'rgba(0, 0, 0, 0.4)',
        }}
        onClick={milestone !== 'messages_15' ? handleSecondaryClick : undefined}
      />

      {/* Modal */}
      <div
        role="dialog"
        aria-modal="true"
        className="relative w-full max-w-[340px] bg-white shadow-2xl overflow-hidden"
        style={{ borderRadius: '24px' }}
      >
        <div className="p-6 pt-8 flex flex-col items-center text-center">
          {/* Icon */}
          <div
            className="w-16 h-16 rounded-full flex items-center justify-center mb-6"
            style={{ backgroundColor: '#F0F0F0' }}
          >
            {config.icon}
          </div>

          {/* Title */}
          <h2
            className="text-2xl font-bold mb-3"
            style={{ color: '#1a1a1a' }}
          >
            {config.title}
          </h2>

          {/* Description */}
          <p
            className="text-base mb-8"
            style={{ color: '#6B7280', lineHeight: '1.5' }}
          >
            {config.description}
          </p>

          {/* Primary CTA */}
          <button
            onClick={handlePrimaryClick}
            className="w-full py-4 rounded-full text-base font-medium transition-colors mb-3"
            style={{
              backgroundColor: '#206E55',
              color: 'white',
            }}
          >
            {config.primaryCtaText}
          </button>

          {/* Secondary CTA */}
          <button
            onClick={handleSecondaryClick}
            className="w-full py-4 rounded-full text-base font-medium transition-colors"
            style={{
              backgroundColor: 'white',
              color: '#1a1a1a',
              border: '1px solid #E5E5E5',
            }}
          >
            {config.secondaryCtaText}
          </button>
        </div>
      </div>
    </div>
  );
}

